const webhookData = $('Refund Status Form Webhook').first()?.json ?? {};
const query = webhookData.query ?? {};
const headers = webhookData.headers ?? {};
const settings = $('Load Global Settings').first()?.json ?? {};
const refundsData = $('List Refunds').first()?.json ?? {};
const refunds = refundsData.rows ?? [refundsData].filter(r => r && typeof r === 'object' && r.id);
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const updateUrl = `${n8nBaseUrl}/webhook/update-refund-status`;
const memberEmailUrl = `${n8nBaseUrl}/webhook/send-member-calculation-email`;
const treasuryEmailUrl = `${n8nBaseUrl}/webhook/send-treasury-refund-request`;
const selectedId = parseInt(clean(query.id), 10);
const selectedRefund = refunds.find(r => r.id === selectedId);
const statuses = ['Requested', 'Awaiting Bank Details', 'Bank Details Received', 'Ready For Treasury', 'Sent To Treasury', 'Paid', 'Rejected', 'Cancelled'];
const statusColors = {
  'Requested': '#6b7785',
  'Awaiting Bank Details': '#f2994a',
  'Bank Details Received': '#27ae60',
  'Ready For Treasury': '#27ae60',
  'Sent To Treasury': '#2f80d8',
  'Paid': '#1f7a4d',
  'Rejected': '#b93a3a',
  'Cancelled': '#b93a3a'
};
const formatMoney = (value) => {
  if (value === null || value === undefined) return 'N/A';
  return `£${Number(value).toFixed(2)}`;
};
const formatDate = (value) => {
  if (!value) return 'N/A';
  return new Date(value).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
};
const refundRows = refunds.map(r => {
  const isSelected = r.id === selectedId;
  const statusColor = statusColors[r.status] || '#6b7785';
  return `<tr class="${isSelected ? 'selected' : ''}" onclick="selectRefund(${r.id})">
    <td>${r.id}</td>
    <td>${escapeHtml(r.refund_for)}</td>
    <td>${escapeHtml(r.membership || '')}</td>
    <td>${formatMoney(r.refund)}</td>
    <td><span class="status-badge" style="background:${statusColor}">${escapeHtml(r.status || 'Unknown')}</span></td>
    <td>${formatDate(r.created_at)}</td>
  </tr>`;
}).join('');
const statusOptions = statuses.map(s => `<option value="${escapeHtml(s)}"${selectedRefund && selectedRefund.status === s ? ' selected' : ''}>${escapeHtml(s)}</option>`).join('');
const selectedSection = selectedRefund ? `
  <div class="refund-details">
    <h2>Update Status</h2>
    <form action="${escapeHtml(updateUrl)}" method="POST">
      <input type="hidden" name="id" value="${selectedRefund.id}">
      <input type="hidden" name="return_url" value="${escapeHtml(n8nBaseUrl)}/webhook/refund-status-form?id=${selectedRefund.id}">
      <div class="detail-row"><label>Refund ID</label><span>${selectedRefund.id}</span></div>
      <div class="detail-row"><label>Member</label><span>${escapeHtml(selectedRefund.refund_for)}</span></div>
      <div class="detail-row"><label>Membership</label><span>${escapeHtml(selectedRefund.membership || 'N/A')}</span></div>
      <div class="detail-row"><label>Reason</label><span>${escapeHtml(selectedRefund.reason || 'N/A')}</span></div>
      <div class="detail-row"><label>Amount Paid</label><span>${formatMoney(selectedRefund.amount)}</span></div>
      <div class="detail-row"><label>Refund Amount</label><span class="refund-amount">${formatMoney(selectedRefund.refund)}</span></div>
      <div class="form-group"><label for="status">Status</label><select name="status" id="status" required>${statusOptions}</select></div>
      <div class="form-group"><label for="notes">Notes</label><textarea name="notes" id="notes" rows="3">${escapeHtml(selectedRefund.notes || '')}</textarea></div>
      <div class="email-tracking"><h3>Email Tracking</h3>
        <div class="detail-row"><label>Request Email ID</label><input type="text" name="request_email_message_id" value="${escapeHtml(selectedRefund.request_email_message_id || '')}"></div>
        <div class="detail-row"><label>Bank Details Email ID</label><input type="text" name="bank_details_message_id" value="${escapeHtml(selectedRefund.bank_details_message_id || '')}"></div>
        <div class="detail-row"><label>Treasury Email ID</label><input type="text" name="treasury_email_message_id" value="${escapeHtml(selectedRefund.treasury_email_message_id || '')}"></div>
      </div>
      <button type="submit" class="submit-btn">Update Status</button>
    </form>
    ${selectedRefund.status === 'Requested' ? `<div class="member-email-section"><h3>Bank Details Request</h3><p>Request the member's bank details for this refund.</p><form action="${escapeHtml(memberEmailUrl)}" method="POST" target="_blank"><input type="hidden" name="refund_id" value="${selectedRefund.id}"><input type="hidden" name="return_url" value="${escapeHtml(n8nBaseUrl)}/webhook/refund-status-form?id=${selectedRefund.id}"><div class="form-group"><label for="member_email">Member Email (optional)</label><input type="email" name="member_email" placeholder="member@example.com"></div><button type="submit" class="email-btn">Request Bank Details from Member</button></form></div>` : ''}
    ${selectedRefund.status === 'Ready For Treasury' ? `<div class="treasury-email-section"><h3>Treasury Handoff</h3><p>Send the refund request to treasury for processing.</p><form action="${escapeHtml(treasuryEmailUrl)}" method="POST" target="_blank"><input type="hidden" name="refund_id" value="${selectedRefund.id}"><input type="hidden" name="return_url" value="${escapeHtml(n8nBaseUrl)}/webhook/refund-status-form?id=${selectedRefund.id}"><div class="form-group"><label for="treasury_email">Treasury Email</label><input type="email" name="treasury_email" placeholder="treasury.avondaleltc@gmail.com"></div><div class="checkbox-wrap"><input type="checkbox" name="test_mode" value="1" checked> Test mode</div><button type="submit" class="treasury-btn">Send to Treasury</button></form></div>` : ''}
  </div>
` : '<div class="no-selection"><p>Select a refund from the list to update its status.</p></div>';
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Refund Status Management</title>
  <style>
    :root { --bg: #f7f8fc; --panel: #ffffff; --ink: #2e3d4e; --muted: #6b7785; --line: #e2e8f0; --accent: #509ee3; }
    * { box-sizing: border-box; }
    body { margin: 0; padding: 24px; background: var(--bg); font-family: Lato, 'Helvetica Neue', Arial, sans-serif; color: var(--ink); }
    .wrap { max-width: 1200px; margin: 0 auto; display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
    .panel { background: var(--panel); border: 1px solid var(--line); border-radius: 18px; box-shadow: 0 18px 40px rgba(53,72,91,.08); padding: 28px; }
    h1 { margin: 0 0 20px; font-size: 28px; }
    h2 { margin: 0 0 16px; font-size: 20px; }
    h3 { margin: 16px 0 12px; font-size: 14px; text-transform: uppercase; letter-spacing: .05em; color: var(--muted); }
    table { width: 100%; border-collapse: collapse; }
    th, td { padding: 12px 8px; text-align: left; border-bottom: 1px solid var(--line); }
    th { font-size: 12px; text-transform: uppercase; letter-spacing: .05em; color: var(--muted); font-weight: 700; }
    tr { cursor: pointer; transition: background 0.15s; }
    tr:hover { background: #f8f9fc; }
    tr.selected { background: #eef2f7; }
    .status-badge { display: inline-block; padding: 4px 10px; border-radius: 999px; color: white; font-size: 12px; font-weight: 700; }
    .detail-row { display: flex; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid var(--line); }
    .detail-row label { font-weight: 700; color: var(--muted); }
    .detail-row span, .detail-row input { color: var(--ink); }
    .detail-row input { width: 60%; padding: 8px 12px; border: 1px solid var(--line); border-radius: 8px; font-size: 14px; }
    .refund-amount { font-size: 18px; font-weight: 700; color: var(--accent); }
    .form-group { margin: 16px 0; }
    .form-group label { display: block; margin-bottom: 6px; font-weight: 700; color: var(--muted); }
    .form-group select, .form-group textarea, .form-group input { width: 100%; padding: 10px 12px; border: 1px solid var(--line); border-radius: 8px; font-size: 14px; font-family: inherit; }
    .email-tracking { margin-top: 20px; padding-top: 16px; border-top: 2px solid var(--line); }
    .submit-btn { width: 100%; padding: 14px; background: linear-gradient(135deg, var(--accent) 0%, #2f80d8 100%); color: white; border: none; border-radius: 999px; font-size: 16px; font-weight: 700; cursor: pointer; margin-top: 20px; }
    .email-btn { width: 100%; padding: 14px; background: linear-gradient(135deg, #27ae60 0%, #1e8449 100%); color: white; border: none; border-radius: 999px; font-size: 16px; font-weight: 700; cursor: pointer; margin-top: 12px; }
    .treasury-btn { width: 100%; padding: 14px; background: linear-gradient(135deg, #2f80d8 0%, #1a5276 100%); color: white; border: none; border-radius: 999px; font-size: 16px; font-weight: 700; cursor: pointer; margin-top: 12px; }
    .member-email-section, .treasury-email-section { margin-top: 24px; padding: 20px; border-radius: 14px; }
    .member-email-section { background: #f0f9f4; border: 1px solid #c8e6d9; }
    .member-email-section h3 { color: #1e8449; }
    .treasury-email-section { background: #eaf2f8; border: 1px solid #c3d9e6; }
    .treasury-email-section h3 { color: #1a5276; }
    .no-selection { text-align: center; color: var(--muted); padding: 40px 20px; }
    @media (max-width: 900px) { .wrap { grid-template-columns: 1fr; } }
  </style>
</head>
<body>
  <div class="wrap">
    <div class="panel">
      <h1>Refunds</h1>
      <table>
        <thead><tr><th>ID</th><th>Member</th><th>Membership</th><th>Refund</th><th>Status</th><th>Created</th></tr></thead>
        <tbody>${refundRows || '<tr><td colspan="6">No refunds</td></tr>'}</tbody>
      </table>
    </div>
    <div class="panel">${selectedSection}</div>
  </div>
  <script>function selectRefund(id) { window.location.href = '?id=' + id; }</script>
</body>
</html>`;
return [{ json: { html } }];
